72	func appendPreClaimIntakeOverrideHonoredEvent(store ExecuteBeadLoopStore, beadID, actor, findingFingerprint, promptFingerprint string, at time.Time) {
73		if store == nil {
74			return
75		}
76		body, _ := json.Marshal(map[string]any{
77			"rule_id":                     "pre_claim_intake.operator_required",
78			"decision_source":             "operator_override",
79			"policy_mode":                 "override",
80			"decision":                    "continue",
81			"reason":                      "operator acceptance already covers the current readiness finding",
82			"fingerprint":                 findingFingerprint,
83			"prompt_fingerprint":          promptFingerprint,
84			"accepted_fingerprint":        findingFingerprint,
85			"accepted_prompt_fingerprint": promptFingerprint,
86		})
87		_ = store.AppendEvent(beadID, bead.BeadEvent{
88			Kind:      "pre_claim_intake.warn",
89			Summary:   "operator_override_honored",
90			Body:      string(body),
91			Actor:     actor,
92			Source:    "ddx work",
93			CreatedAt: at,
94		})
95	}
