				Detail:        "blocked by readiness",
				OutcomeReason: "transport",
				SessionID:     "sess-override-false",
				ResultRev:     "override-false",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
